import type React from 'react';

import { Portal as PortalPrimitive } from '@radix-ui/react-portal';

import { cn } from '../utils/cn';

type OverlayProps = React.ComponentProps<'div'> & { open?: boolean };

/**
 * A blocking overlay that can be used to dim the background and prevent
 * interaction with the underlying content.
 *
 * **Note**: This component exists to solve a specific and urgent use case, but
 * is not part of the design system and lacks some a11y details. Do not use
 * generally.
 */
export function Overlay({ className, open = false, ...props }: OverlayProps) {
  return open ? (
    <PortalPrimitive>
      <div
        role="status"
        aria-busy="true"
        data-slot="overlay"
        className={cn(
          'fixed inset-0 z-50 bg-black/50',
          'pointer-events-auto',
          className
        )}
        {...props}
      />
    </PortalPrimitive>
  ) : null;
}

/**
 * Content centered on both axes within the overlay.
 */
export function OverlayContent({
  className,
  ...props
}: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="overlay-content"
      className={cn(
        'fixed left-1/2 top-1/2 z-50 grid w-auto max-w-[calc(100%-2rem)] -translate-x-1/2 -translate-y-1/2',
        'gap-4 rounded border bg-background p-3 shadow-lg md:gap-6',
        'pointer-events-none select-none',
        className
      )}
      {...props}
    />
  );
}
